SELECT 
FROM ${tableName}
WHERE user_id = #{userId}
  AND currency = #{currency}
  AND status = 0
  AND order_type IN (11, 23)
  AND create_time >= #{startTime}
  AND create_time < #{endTime}
ORDER BY id ASC
LIMIT #{limitSize}

SELECT 
FROM ${tableName}
WHERE user_id = #{userId}
  AND currency = #{currency}
  AND status = 1
  AND total_balance_after IS NOT NULL
  AND create_time >= #{startTime}
  AND create_time < #{endTime}
  AND account_seq < #{accountSeq}
ORDER BY account_seq DESC
LIMIT 1

