FROM ${tableName}
WHERE user_id = #{userId}
  AND currency = #{currency}
  AND status = 3
  AND total_balance_before IS NULL
  AND total_balance_after IS NULL
  AND create_time >= #{startTime}
  AND create_time < #{endTime}
ORDER BY id ASC
LIMIT #{limitSize}

SELECT MAX(account_seq)
FROM account_statements
WHERE user_id = #{userId}
  AND currency = #{currency}
  AND account_seq IS NOT NULL

